export const getMarketData = async () => {
    try {
        // Tarayıcıdaki CORS (Güvenlik) engeline takılmamak için güvenli bir aracı kullanıyoruz
        const targetUrl = 'https://finans.truncgil.com/today.json';
        const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(targetUrl)}`;

        const response = await fetch(proxyUrl);
        const data = await response.json();

        // Çekeceğimiz anahtar kelimeler ve onlara koyacağımız isimler
        const selected = [
            { key: 'USD', label: 'USD/TRY', prefix: '₺' },
            { key: 'EUR', label: 'EUR/TRY', prefix: '₺' },
            { key: 'GBP', label: 'GBP/TRY', prefix: '₺' },
            { key: 'ons', label: 'ONS', prefix: '$' },
            { key: 'gram-altin', label: 'GRAM', prefix: '₺' },
            { key: 'ceyrek-altin', label: 'ÇEYREK', prefix: '₺' },
            { key: 'cumhuriyet-altini', label: 'CUMHURİYET', prefix: '₺' },
            { key: 'gumus', label: 'GÜMÜŞ', prefix: '₺' }
        ];

        const formattedData = selected.map(item => {
            const rawItem = data[item.key];
            if (!rawItem) return null;

            // "%-0,26" eksi yönlü mü diye kontrol ediyoruz
            const trend = rawItem['Değişim'].includes('-') ? 'down' : 'up';

            // Satış fiyatını gösteriyoruz
            const price = rawItem['Satış'].startsWith('$') 
                ? rawItem['Satış'] 
                : `${item.prefix}${rawItem['Satış']}`;

            return {
                symbol: item.label,
                price: price,
                trend: trend
            };
        }).filter(Boolean); // null olanları temizle

        return formattedData;

    } catch (error) {
        console.error("Canlı veri çekilemedi:", error);
        // Geçici veri (İnternet kesilmesi gibi durumlar için yedek)
        return [
            { symbol: 'ONS', price: '$2,345', trend: 'up' },
            { symbol: 'GRAM', price: '₺2,450', trend: 'up' },
            { symbol: 'USD/TRY', price: '₺32.65', trend: 'down' }
        ];
    }
};
